{
 "level": "A1–A2",
 "intro": "In this topic you will learn the <strong>8 main parts of speech</strong> of English: nouns, verbs, adjectives, adverbs, pronouns, prepositions, conjunctions and exclamations.",
 "rules": [
 {
 "label": "Content Words",
 "color": "emerald",
 "text": "<strong>Nouns, Verbs, Adjectives, Adverbs</strong> - carry the main meaning:",
 "example": "The happy cat runs quickly."
 },
 {
 "label": "Function Words",
 "color": "blue",
 "text": "<strong>Pronouns, Prepositions, Conjunctions</strong> - connect words:",
 "example": "She is at home and I am here."
 },
 {
 "label": "Interjections",
 "color": "amber",
 "text": "<strong>Exclamations</strong> - express emotions:",
 "example": "Wow! Oh! Oops!"
 }
 ]
}

{
 "title": "1. Overview of the 8 Parts of Speech",
 "intro": "English has 8 main parts of speech:",
 "items": [
 {
 "label": "Noun",
 "title": "Noun",
 "subtitle": "Names of objects, people, places, ideas (cat, John, city, love)"
 },
 {
 "label": "Verb",
 "title": "Verb",
 "subtitle": "Actions or states (run, eat, be, have)"
 },
 {
 "label": "Adjective",
 "title": "Adjective",
 "subtitle": "Describes nouns (big, red, beautiful, smart)"
 },
 {
 "label": "Adverb",
 "title": "Adverb",
 "subtitle": "Describes verbs, adjectives (quickly, very, often)"
 },
 {
 "label": "Pronoun",
 "title": "Pronoun",
 "subtitle": "Replaces nouns (I, you, he, she, it, they)"
 },
 {
 "label": "Preposition",
 "title": "Preposition",
 "subtitle": "Shows a relationship (in, on, at, under, between)"
 },
 {
 "label": "Conjunction",
 "title": "Conjunction",
 "subtitle": "Connects words and sentences (and, but, or, because)"
 },
 {
 "label": "Interjection",
 "title": "Exclamation",
 "subtitle": "Expresses emotions (Oh! Wow! Oops! Hey!)"
 }
 ]
}

{
 "title": "2. Nouns - Nouns",
 "sections": [
 {
 "label": "What is a noun? (cat is a thing)",
 "color": "emerald",
 "description": "<strong>Noun</strong> names a person, place, thing, or idea.",
 "examples": [
 {
 "en": "The cat is sleeping.",
 "ua": "The cat is sleeping."
 },
 {
 "en": "Mary lives in London.",
 "ua": "Mary lives in London."
 },
 {
 "en": "Love is important.",
 "ua": "Love is important."
 }
 ]
 },
 {
 "label": "Types of nouns",
 "color": "sky",
 "description": "Nouns are <strong>common</strong> (common) and <strong>proper</strong> (proper).",
 "examples": [
 {
 "en": "common: dog, city, book",
 "ua": "common: dog, city, book"
 },
 {
 "en": "proper: Tom, Paris, Monday",
 "ua": "proper: Tom, Paris, Monday"
 }
 ],
 "note": "<strong>Proper nouns</strong> are always capitalized."
 }
 ]
}

{
 "title": "3. Verbs - Verbs",
 "sections": [
 {
 "label": "What is a verb? (run - action)",
 "color": "emerald",
 "description": "<strong>Verb</strong> expresses an action or a state.",
 "examples": [
 {
 "en": "She runs every morning.",
 "ua": "She runs every morning."
 },
 {
 "en": "He is a teacher.",
 "ua": "He is a teacher."
 },
 {
 "en": "They have two children.",
 "ua": "They have two children."
 }
 ]
 },
 {
 "label": "Types of verbs",
 "color": "sky",
 "description": "Main types: <strong>action verbs</strong>, <strong>linking verbs</strong>, <strong>auxiliary verbs</strong>.",
 "examples": [
 {
 "en": "action: run, eat, write, play play",
 "ua": "action: run, eat, write, play play"
 },
 {
 "en": "linking: be, seem, become",
 "ua": "linking: be, seem, become"
 },
 {
 "en": "auxiliary: do, have, will, can",
 "ua": "auxiliary: do, have, will, can"
 }
 ]
 }
 ]
}

{
 "title": "4. Adjectives - Adjectives",
 "sections": [
 {
 "label": "What is an adjective",
 "color": "emerald",
 "description": "<strong>Adjective</strong> is a word that describes or modifies a noun.",
 "examples": [
 {
 "en": "a big house",
 "ua": "a big house"
 },
 {
 "en": "a beautiful flower",
 "ua": "a beautiful flower"
 },
 {
 "en": "The coffee is hot.",
 "ua": "The coffee is hot."
 }
 ]
 },
 {
 "label": "Adjective position",
 "color": "sky",
 "description": "The adjective is <strong>before the noun</strong> or <strong>after linking verb</strong>.",
 "examples": [
 {
 "en": "a tall man (before a noun)",
 "ua": "a tall man (before a noun)"
 },
 {
 "en": "The man is tall. (after linking verb)",
 "ua": "The man is tall. (after linking verb)"
 }
 ],
 "note": "In English, the adjective <strong>does not change</strong> by gender and number: a tall man, a tall woman, tall people."
 }
 ]
}

{
 "title": "5. Adverbs - Adverbs",
 "sections": [
 {
 "label": "What is an adverb",
 "color": "emerald",
 "description": "<strong>Adverb</strong> is a word that modifies a verb, adjective or other adverb.",
 "examples": [
 {
 "en": "She runs quickly.",
 "ua": "She runs quickly."
 },
 {
 "en": "He is very tall.",
 "ua": "He is very tall."
 },
 {
 "en": "She speaks too quietly.",
 "ua": "She speaks too quietly."
 }
 ]
 },
 {
 "label": "Formation of adverbs",
 "color": "sky",
 "description": "Many adverbs are formed by adding <strong>-ly</strong> to an adjective.",
 "examples": [
 {
 "en": "quick → quickly",
 "ua": "quick → quickly"
 },
 {
 "en": "careful → carefully",
 "ua": "careful → carefully"
 },
 {
 "en": "happy → happily",
 "ua": "happy → happily"
 }
 ],
 "note": "Exception: <strong>good → well</strong> (not goodly), <strong>fast → fast</strong> (same form)."
 }
 ]
}

{
 "title": "6. Pronouns - Pronouns",
 "sections": [
 {
 "label": "What is a pronoun",
 "color": "emerald",
 "description": "<strong>Pronoun</strong> is a word that replaces a noun to avoid repetition.",
 "examples": [
 {
 "en": "Mary is a doctor. She works at a hospital.",
 "ua": "Mary is a doctor. She works at a hospital."
 },
 {
 "en": "The book is interesting. It is about history.",
 "ua": "The book is interesting. It is about history."
 }
 ]
 },
 {
 "label": "Types of pronouns",
 "color": "sky",
 "description": "Main types: <strong>personal</strong> (personal), <strong>possessive</strong> (possessive), <strong>demonstrative</strong> (indicative).",
 "examples": [
 {
 "en": "personal: I, you, he, she, it, we, they",
 "ua": "personal: I, you, he, she, it, we, they"
 },
 {
 "en": "possessive: my, your, his, her, our, their",
 "ua": "possessive: my, your, his, her, our, their"
 },
 {
 "en": "demonstrative: this, that, these, those",
 "ua": "demonstrative: this, that, these, those"
 }
 ]
 }
 ]
}

{
 "title": "7. Prepositions - Prepositions",
 "sections": [
 {
 "label": "What is a preposition",
 "color": "emerald",
 "description": "<strong>Preposition</strong> is a word that shows the relationship between words (place, time, direction).",
 "examples": [
 {
 "en": "The book is on the table.",
 "ua": "The book is on the table."
 },
 {
 "en": "I wake up at 7 a.m.",
 "ua": "I wake up at 7 a.m."
 },
 {
 "en": "She walked to the park.",
 "ua": "She walked to the park."
 }
 ]
 },
 {
 "label": "Most common prepositions",
 "color": "sky",
 "description": "Basic prepositions of place, time and motion.",
 "examples": [
 {
 "en": "place: in, on, at, under, behind, between",
 "ua": "place: in, on, at, under, behind, between"
 },
 {
 "en": "time: at, On, in, before, after Conjunctions - Conjunctions",
 "ua": "time: at, On, in, before, after Conjunctions - Conjunctions"
 },
 {
 "en": "movement: to, from, into, out of",
 "ua": "movement: to, from, into, out of"
 }
 ]
 }
 ]
}

{
 "title": "8. Conjunctions",
 "sections": [
 {
 "label": "What is a conjunction",
 "color": "emerald",
 "description": "<strong>Conjunction</strong> is a word that connects words, phrases or sentences.",
 "examples": [
 {
 "en": "I like tea and coffee.",
 "ua": "I like tea and coffee."
 },
 {
 "en": "She is smart but lazy.",
 "ua": "She is smart but lazy."
 },
 {
 "en": "I stayed home because it was raining.",
 "ua": "I stayed home because it was raining."
 }
 ]
 },
 {
 "label": "Types of conjunctions",
 "color": "sky",
 "description": "<strong>Coordinating</strong> (equal) and Subordinating conjunctions.",
 "examples": [
 {
 "en": "coordinating: and, but, or, so, yet",
 "ua": "coordinating: and, but, or, so, yet"
 },
 {
 "en": "subordinating: because, if, when, although",
 "ua": "subordinating: because, if, when, although"
 }
 ],
 "note": "<strong>FANBOYS</strong> is an acronym for For, And, Nor, But, Or, Yet, So."
 }
 ]
}

{
 "title": "9. Interjections - Interjections",
 "sections": [
 {
 "label": "What is an interjection",
 "color": "emerald",
 "description": "<strong>Interjection</strong> is a word or phrase that expresses an emotion or reaction.",
 "examples": [
 {
 "en": "Wow! That is amazing!",
 "ua": "Wow! That is amazing!"
 },
 {
 "en": "Oops! I made a mistake.",
 "ua": "Oops! I made a mistake."
 },
 {
 "en": "Hurray! We won!",
 "ua": "Hurray! We won!"
 }
 ]
 },
 {
 "label": "Common Exclamations",
 "color": "sky",
 "description": "Exclamations often stand alone and are separated by an exclamation mark.",
 "examples": [
 {
 "en": "Oh! Ah! Wow! Hey! Ouch!",
 "ua": "Oh! Ah! Wow! Hey! Ouch!"
 },
 {
 "en": "Well, I think so.",
 "ua": "Well, I think so."
 }
 ],
 "note": "Exclamations add emotion to speech, but in formal writing they are avoided."
 }
 ]
}

{
 "title": "10. Summary table of parts of speech",
 "intro": "All 8 parts of speech and their functions:",
 "rows": [
 {
 "en": "Noun",
 "ua": "Noun",
 "note": "calls: cat, city, love"
 },
 {
 "en": "Verb",
 "ua": "Verb",
 "note": "action/state: run, is, have"
 },
 {
 "en": "Adjective",
 "ua": "Adjective",
 "note": "describes noun: big, red"
 },
 {
 "en": "Adverb",
 "ua": "Adverb",
 "note": "modifies a verb: quickly, very"
 },
 {
 "en": "Pronoun",
 "ua": "Pronoun",
 "note": "replaces a noun: I, she, they"
 },
 {
 "en": "Preposition",
 "ua": "Preposition",
 "note": "relation: in, on, at"
 },
 {
 "en": "Conjunction",
 "ua": "Conjunction",
 "note": "connects: and, but, because"
 },
 {
 "en": "Interjection",
 "ua": "Interjection",
 "note": "emotions: Wow! Oh! Oops!"
 }
 ],
 "warning": "📌 One word can be different parts of speech depending on the context: <strong>run</strong> (verb: I run) vs <strong>run</strong> (noun: a morning run)."
}

{
 "title": "11. Common mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Confusion between an adjective and an adverb.",
 "wrong": "She speaks English good.",
 "right": "​​​​ <span class=\"font-mono\">She speaks English well.</span>"
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Using an adjective instead of an adverb.",
 "wrong": "He runs quickly.",
 "right": "​​​​​​​​ pronoun."
 },
 {
 "label": "Mistake 3",
 "color": "sky",
 "title": "Choosing the wrong pronoun.",
 "wrong": "Me and Tom went to school.",
 "right": " ✅ <span class=\"font-mono\">Tom and I went to school.</span>"
 },
 {
 "label": "Error 4",
 "color": "purple",
 "title": "Omission of the article before the noun.",
 "wrong": "I have cat.",
 "right": " ✅ <span class=\"font-mono\">I have a cat.</span>"
 }
 ]
}

{
 "title": "13. Practice",
 "select_title": "Exercise 1. Identify the part of speech",
 "select_intro": "Determine what part of speech the selected word is.",
 "selects": [
 {
 "label": "The CAT is sleeping. (noun / verb / adjective)",
 "prompt": "What part of speech?"
 },
 {
 "label": "She QUICKLY finished her work. (adjective / adverb / noun)",
 "prompt": "What part of speech?"
 },
 {
 "label": "They went TO the park. (conjunction/preposition/adverb) words.",
 "prompt": "What part of speech?"
 }
 ],
 "options": [
 "a",
 "b",
 "c"
 ],
 "input_title": "Exercise 2. Choose the correct form",
 "input_intro": "Choose the correct word form.",
 "inputs": [
 {
 "before": "She sings (beautiful / beautifully)",
 "after": "→"
 },
 {
 "before": "He is a (good / well) student",
 "after": "→"
 },
 {
 "before": "They work (hard / hardly) every day. (noun), runs (verb), quickly (adverb).",
 "after": "→"
 }
 ],
 "rephrase_title": "Exercise 3. Identify all parts of speech",
 "rephrase_intro": "Name the part of speech for each word.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "The happy dog runs quickly.",
 "example_target": "The (article), happy (adjective), dog (noun), runs (verb), quickly (adverb)."
 },
 {
 "original": "1. She and I went to school yesterday.",
 "placeholder": "Identify the parts of speech"
 },
 {
 "original": "2. Wow! The big cat is sleeping on the soft bed.",
 "placeholder": "Identify the parts of speech"
 }
 ]
}

{
 "title": "Keep learning",
 "items": [
 {
 "label": "Parts of Speech - Parts of speech",
 "current": true
 },
 {
 "label": "Basic Word Order - Word Order in Affirmation",
 "current": false
 },
 {
 "label": "Word Order in Questions and Negatives - Questions and Negatives",
 "current": false
 }
 ]
}
